// Generated: Liberation Sans (SIL OFL, see LICENSE in this directory),
// embedded as data URLs so PDF rendering needs no filesystem access in
// serverless. Metric-compatible with Arial/Helvetica; full Latin + Greek
// coverage for the model form glyphs (Ω, Δ, superscripts).
const ttf = (b64: string) => `data:font/truetype;base64,${b64}`;
export const FORM_FONT_REGULAR = ttf("");
export const FORM_FONT_BOLD = ttf("");
export const FORM_FONT_ITALIC = ttf("");
